import json

import yaml

from prompty.model import EngineEvent


def test_load_json_engineevent():
    json_data = r"""
    {
      "id": "evt_abc123",
      "timestamp": "2025-01-01T00:00:00Z",
      "sessionId": "sess_abc123",
      "turnId": "turn_abc123",
      "runId": "run_abc123"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = EngineEvent.load(data)
    assert instance is not None
    assert instance.id == "evt_abc123"
    assert instance.timestamp == "2025-01-01T00:00:00Z"
    assert instance.session_id == "sess_abc123"
    assert instance.turn_id == "turn_abc123"
    assert instance.run_id == "run_abc123"


