def test_roundtrip_json_engineevent():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "id": "evt_abc123",
      "timestamp": "2025-01-01T00:00:00Z",
      "sessionId": "sess_abc123",
      "turnId": "turn_abc123",
      "runId": "run_abc123"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = EngineEvent.load(original_data)
    saved_data = instance.save()
    reloaded = EngineEvent.load(saved_data)
    assert reloaded is not None
    assert reloaded.id == "evt_abc123"
    assert reloaded.timestamp == "2025-01-01T00:00:00Z"
    assert reloaded.session_id == "sess_abc123"
    assert reloaded.turn_id == "turn_abc123"
    assert reloaded.run_id == "run_abc123"


